// components/FormRenderer.tsx

import React, {useCallback, useMemo} from 'react';
import type {Control, FieldValues, UseFormGetValues} from 'react-hook-form';
import type {GroupFieldConfigs, IFormElement} from '@lmb-it/kitsconcerto-types';
import {FieldWrapper} from '../layout/FieldWrapper';

// Import all your "dumb" field components
import {
    Checkboxes,
    ColorPicker,
    CombinedElement,
    ContainerElement,
    DateField,
    FileUploader,
    Group,
    InputNumber,
    InputText,
    ListBox,
    Location,
    NormalSelect,
    ObjectElement,
    Password,
    Phone,
    Radios,
    Select,
    Switch,
    TagsSelect,
    Textarea,
    TreeSelect
} from '../fields';
import {Grid} from "../../../_compat";
import type {IStyleClasses} from "@lmb-it/kitsconcerto-types";

// ... import all other field components

interface FormRendererProps<T extends FieldValues> extends GroupFieldConfigs<T>{
    elements: IFormElement<T>[];
    control: Control<T>;
    getValues: UseFormGetValues<T>;
    parentPath?: string; // ✨ Pass down the parent path for nesting
    grid?: IStyleClasses;
    focusedField?: string;
    setFocusedField: React.Dispatch<React.SetStateAction<string>>;
}

export const FormRenderer = <T extends FieldValues>({
                                                        elements,
                                                        control,
                                                        getValues,
                                                        groupField,
                                                        grid = {},
                                                        parentPath = '',
                                                        focusedField, setFocusedField
                                                    }: FormRendererProps<T>) => {


    const getElement = useCallback((elementType: string) => {

        switch (elementType) {

            case 'Email':
            case 'Text':
                return InputText;
            case 'Number':
                return InputNumber;
            case 'Password':
                return Password;
            case 'Location':
                return Location;
            case 'Phone':
                return Phone
            case 'Date':
                return DateField
            case 'ColorPicker':
                return ColorPicker
            case 'Radios':
                return Radios
            case 'Textarea':
                return Textarea
            case 'Image':
            case 'File':
                return FileUploader
            case 'Switch':
                return Switch
            case 'Checkbox':
                return Checkboxes
            case 'Select':
                return NormalSelect
            case 'TreeSelect':
                return TreeSelect
            case 'Tags':
                return TagsSelect
            case 'ListBox':
                return ListBox
            case 'Multiselect':
                return Select
            case 'Group':
                return Group
            case 'Object':
                return ObjectElement
            case 'Container':
                return ContainerElement
            case 'Combined':
                return CombinedElement
            // default:
            //     return <Flex/>;
        }
    }, []);

    return (
        <Grid
            columns={12}
            rowGap={10}
            colSpan={12}
            columnGap={10}
            w={"full"}
            m={0}
            id={'form-rerender'}
            position={"relative"}
            {...grid as any}
        >
            {elements.map((element) => {

                const FieldComponent = getElement(element.type);

                const elementId = `${parentPath}${element.id as string}`;
                // Build a new element object with the resolved id instead of mutating the prop
                const resolvedElement = elementId !== element.id ? {...element, id: elementId} : element;

                if (!FieldComponent) {
                    console.warn(`No component found for element type: "${resolvedElement.type}"`);
                    return null;
                }


                return (
                    <FieldWrapper
                        key={elementId}
                        element={resolvedElement}
                        control={control}
                        groupField={groupField}
                        getValues={getValues}
                        focusedField={focusedField}
                        setFocusedField={setFocusedField}

                    >
                        {(props)=><FieldComponent
                            groupField={groupField}
                            element={resolvedElement}
                            control={control}
                            getValues={getValues}
                            focusedField={focusedField}
                            setFocusedField={setFocusedField}
                            fieldLogic={props}

                        />}
                    </FieldWrapper>
                );
            })}
        </Grid>
    );
};
